const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Set secure HTTP headers (X-Content-Type-Options, CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload attacks
app.use(express.json({ limit: '10kb' }));

// Global rate limiter: 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable the X-Powered-By header to avoid fingerprinting
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const { limit, offset } = req.query;

  if (limit !== undefined) {
    const parsed = Number(limit);
    if (!Number.isInteger(parsed) || parsed < 1 || parsed > 100) {
      return res.status(400).json({ error: 'limit must be an integer between 1 and 100' });
    }
  }

  if (offset !== undefined) {
    const parsed = Number(offset);
    if (!Number.isInteger(parsed) || parsed < 0) {
      return res.status(400).json({ error: 'offset must be a non-negative integer' });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  const start = Number(offset) || 0;
  const end = limit ? start + Number(limit) : users.length;

  res.json(users.slice(start, end));
});

// --- 404 Handler ---
// Catch requests to undefined routes
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Catches synchronous and async errors passed via next(err).
// IMPORTANT: Must have 4 parameters for Express to recognize it as error middleware.
app.use((err, _req, res, _next) => {
  // Log the full error server-side for debugging
  console.error('Unhandled error:', err);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Server Startup ---

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

