const express = require('express');
const helmet = require('helmet');        // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();

// --- Security middleware ---
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Rate limiting: max 100 requests per 15-minute window per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (_req, res) => {
  // In production, emails should be gated behind authentication/authorization
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ];
  res.json(users);
});

// --- 404 handler for undefined routes ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler ---
// Must have 4 parameters so Express recognizes it as an error handler
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
